const items = $input.all();

// Gemini
let geminiText = '';
try { geminiText = (items[0]?.json?.candidates?.[0]?.content?.parts || []).map(p => p.text || '').join('\n'); }
catch (e) { geminiText = 'Gemini: errore'; }

// Perplexity
let perplexityText = '';
try { perplexityText = items[1]?.json?.choices?.[0]?.message?.content || ''; }
catch (e) { perplexityText = 'Perplexity: errore'; }

// OpenAI
let openaiText = '';
try { openaiText = items[2]?.json?.choices?.[0]?.message?.content || ''; }
catch (e) { openaiText = 'OpenAI: errore'; }

// Duffel multi-origin (now from Code node, structured)
let duffelStruct = { error: null, byOrigin: {}, primary: null, recommendedOrigin: null, usedFallback: false, note: '' };
try {
  const d = items[3]?.json;
  if (d?.byOrigin) {
    duffelStruct = {
      primary: d.primary,
      recommendedOrigin: d.recommendedOrigin,
      usedFallback: d.usedFallback,
      note: d.note,
      byOrigin: d.byOrigin,
      error: null
    };
  } else {
    duffelStruct.error = 'no byOrigin in response';
  }
} catch (e) { duffelStruct.error = String(e); }

// Google Maps Transit
let gmapsStruct = { error: null, routes: [] };
try {
  const r = items[4]?.json;
  if (r?.error) {
    gmapsStruct.error = r.error.message || JSON.stringify(r.error);
  } else {
    const routes = (r?.routes || []).slice(0, 3);
    gmapsStruct.routes = routes.map(rt => {
      const legs = rt.legs || [];
      const transitSteps = [];
      for (const leg of legs) {
        for (const s of (leg.steps || [])) {
          if (s.transitDetails) {
            const td = s.transitDetails;
            transitSteps.push({
              vehicle: td.transitLine?.vehicle?.type,
              line: td.transitLine?.nameShort || td.transitLine?.name,
              from: td.stopDetails?.departureStop?.name,
              to: td.stopDetails?.arrivalStop?.name
            });
          }
        }
      }
      return {
        duration: rt.duration,
        distance_km: Math.round((rt.distanceMeters || 0) / 1000),
        steps: transitSteps
      };
    });
  }
} catch (e) { gmapsStruct.error = String(e); }

return [{
  json: {
    gemini: geminiText,
    perplexity: perplexityText,
    openai: openaiText,
    duffel: duffelStruct,
    gmaps: gmapsStruct
  }
}];

// Duffel multi-origin search — when no direct flights from primary, try fallback chain
// Rule (Mirko 2026-04-29): if FLR has no direct, try BLQ, PSA, FCO, LIN in order
const params = JSON.parse($input.first().json.choices[0].message.content);
const dest = params.destination_iata;
const date = params.departure_date;
const passengers = params.passengers || 1;
const TOKEN = process.env.DUFFEL_API_KEY;

const FALLBACK_CHAIN = ['FLR', 'BLQ', 'PSA', 'FCO', 'LIN'];
const primary = params.origin_iata || 'FLR';
const origins = [primary, ...FALLBACK_CHAIN.filter(o => o !== primary)];

const byOrigin = {};
for (const origin of origins) {
  try {
    const data = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.duffel.com/air/offer_requests',
      headers: {
        'Authorization': `Bearer ${TOKEN}`,
        'Duffel-Version': 'v2',
        'Content-Type': 'application/json',
        'Accept': 'application/json'
      },
      body: {
        data: {
          slices: [{origin, destination: dest, departure_date: date}],
          passengers: Array.from({length: passengers}, () => ({type: 'adult'})),
          cabin_class: 'economy'
        }
      },
      json: true,
      timeout: 30000
    });
    if (data.errors) {
      byOrigin[origin] = { error: JSON.stringify(data.errors).slice(0,200), direct: [], any: [] };
      continue;
    }
    const offers = data.data?.offers || [];
    const seen = new Map();
    for (const o of offers) {
      const seg = o.slices[0].segments;
      const k = `${seg[0].marketing_carrier?.iata_code}-${seg[0].marketing_carrier_flight_number}-${seg[0].departing_at}`;
      const price = parseFloat(o.total_amount);
      const existing = seen.get(k);
      if (!existing || existing.price > price) {
        seen.set(k, {
          carrier: seg[0].marketing_carrier?.name,
          flight_number: (seg[0].marketing_carrier?.iata_code || '') + (seg[0].marketing_carrier_flight_number || ''),
          stops: seg.length - 1,
          dep: seg[0].departing_at,
          arr: seg[seg.length-1].arriving_at,
          price,
          currency: o.total_currency,
          op: seg[0].operating_carrier?.name && seg[0].operating_carrier.name !== seg[0].marketing_carrier?.name ? seg[0].operating_carrier.name : null
        });
      }
    }
    const all = Array.from(seen.values()).sort((a,b)=>a.price-b.price);
    byOrigin[origin] = {
      direct: all.filter(o => o.stops === 0).slice(0, 5),
      any: all.slice(0, 5)
    };
  } catch (err) {
    byOrigin[origin] = { error: String(err).slice(0,200), direct: [], any: [] };
  }
}

const primaryHasDirect = (byOrigin[primary]?.direct?.length || 0) > 0;
let recommendedOrigin = primary;
let usedFallback = false;
if (!primaryHasDirect) {
  for (const o of FALLBACK_CHAIN) {
    if (byOrigin[o]?.direct?.length > 0) {
      recommendedOrigin = o;
      usedFallback = true;
      break;
    }
  }
}

return [{
  json: {
    byOrigin,
    primary,
    recommendedOrigin,
    usedFallback,
    originsChecked: origins,
    note: usedFallback ? `Nessun volo diretto da ${primary}, fallback su ${recommendedOrigin}` : `Diretti disponibili da ${primary}`
  }
}];

